import { Component, input, output, signal, effect } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { CardModule } from 'primeng/card';
import { ButtonModule } from 'primeng/button';
import { MessageModule } from 'primeng/message';
import { I18nPipe } from '../../../../core/i18n/i18n.pipe';

@Component({
  selector: 'app-sample-data-step',
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    CardModule,
    ButtonModule,
    MessageModule,
    I18nPipe
  ],
  templateUrl: './sample-data-step.component.html',
  styleUrl: './sample-data-step.component.scss'
})
export class SampleDataStepComponent {
  method = input.required<string>();
  initialSampleJson = input<string>('');
  
  sampleDataComplete = output<{
    sampleJson: string;
  }>();
  
  backClicked = output<void>();

  sampleJson = signal('');
  jsonError = signal<string | null>(null);
  copySuccess = signal(false);

  constructor() {
    // Use effect to load initial value when input changes
    effect(() => {
      const initial = this.initialSampleJson();
      if (initial && !this.sampleJson()) {
        this.sampleJson.set(initial);
        console.log('Loaded initial sample JSON:', initial.substring(0, 100));
      }
    });
  }

  needsPayload(): boolean {
    const m = this.method().toUpperCase();
    return m === 'POST' || m === 'PUT' || m === 'PATCH';
  }

  onJsonChange(value: string): void {
    this.sampleJson.set(value);
    this.validateJson(value);
  }

  validateJson(value: string): void {
    if (!value.trim()) {
      this.jsonError.set(null);
      return;
    }

    try {
      JSON.parse(value);
      this.jsonError.set(null);
    } catch (e: any) {
      this.jsonError.set(e.message);
    }
  }

  isValid(): boolean {
    if (!this.needsPayload()) {
      return true; // GET/DELETE don't need payload
    }
    
    return this.sampleJson().trim() !== '' && this.jsonError() === null;
  }

  onNext(): void {
    this.sampleDataComplete.emit({
      sampleJson: this.sampleJson()
    });
  }

  onBack(): void {
    this.backClicked.emit();
  }

  loadSampleFile(event: Event): void {
    const input = event.target as HTMLInputElement;
    if (!input.files || input.files.length === 0) return;

    const file = input.files[0];
    const reader = new FileReader();
    
    reader.onload = (e) => {
      const content = e.target?.result as string;
      this.onJsonChange(content);
    };
    
    reader.readAsText(file);
  }

  formatJson(): void {
    const json = this.sampleJson().trim();
    if (!json) return;

    try {
      const parsed = JSON.parse(json);
      const formatted = JSON.stringify(parsed, null, 2);
      this.sampleJson.set(formatted);
      this.jsonError.set(null);
    } catch (e: any) {
      // If JSON is invalid, show error but don't change the content
      this.jsonError.set(e.message);
    }
  }

  copyJson(): void {
    const json = this.sampleJson();
    if (!json.trim()) return;

    this.writeTextToClipboard(json).then(() => {
      this.copySuccess.set(true);
      setTimeout(() => this.copySuccess.set(false), 2000);
    });
  }

  private async writeTextToClipboard(text: string): Promise<void> {
    try {
      await navigator.clipboard.writeText(text);
    } catch {
      const el = document.createElement('textarea');
      el.value = text;
      el.style.position = 'fixed';
      el.style.opacity = '0';
      document.body.appendChild(el);
      el.select();
      document.execCommand('copy');
      document.body.removeChild(el);
    }
  }
}
